import { useState, useEffect, useCallback } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './ExecutionAlgosPage.module.css';

const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

function ProgressBar({ pct, color }) {
  return (
    <div className={s.progressTrack}>
      <div
        className={s.progressFill}
        style={{
          width: `${Math.min(100, Math.max(0, pct))}%`,
          background: color || T.blue,
        }}
      />
    </div>
  );
}

function AlgoBadge({ algo }) {
  const cfg = {
    VWAP: { color: T.blue, bg: T.blue + '18' },
    TWAP: { color: T.purple, bg: T.purple + '18' },
    MARKET: { color: T.amber, bg: T.amber + '18' },
    LIMIT: { color: T.green, bg: T.green + '18' },
  };
  const c = cfg[algo] || { color: T.textSec, bg: T.surface2 };
  return (
    <span
      className={s.algoBadge}
      style={{ background: c.bg, border: `1px solid ${c.color}44`, color: c.color }}
    >
      {algo || 'UNKNOWN'}
    </span>
  );
}

export default function ExecutionAlgosPage() {
  usePageTitle('Execution Algos');
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Estimator form
  const [estSymbol, setEstSymbol] = useState('');
  const [estQty, setEstQty] = useState('');
  const [estSide, setEstSide] = useState('BUY');
  const [estResult, setEstResult] = useState(null);
  const [estLoading, setEstLoading] = useState(false);

  const fetchStatus = useCallback(async () => {
    try {
      const res = await fetch(`${getApiBase()}/execution/algos/status`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json();
      setStatus(json);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchStatus();
    const iv = setInterval(fetchStatus, 5000);
    return () => clearInterval(iv);
  }, [fetchStatus]);

  const handleEstimate = async (e) => {
    e.preventDefault();
    if (!estSymbol || !estQty) return;
    setEstLoading(true);
    try {
      const params = new URLSearchParams({ symbol: estSymbol.toUpperCase(), qty: estQty, side: estSide });
      const res = await fetch(`${getApiBase()}/execution/algos/estimate?${params}`, { method: 'POST' });
      const json = await res.json();
      setEstResult(json);
    } catch (err) {
      setEstResult({ error: err.message });
    } finally {
      setEstLoading(false);
    }
  };

  const active = status?.active || [];
  const completed = status?.completed || [];
  const fmt = (v, d = 2) => v != null ? Number(v).toFixed(d) : '--';

  return (
    <div className={s.page}>
      <h1 className={s.title}>Execution Algorithms</h1>
      <p className={s.subtitle}>
        VWAP/TWAP execution algorithms — impact estimation and live execution monitoring
      </p>

      {error && (
        <GlassPanel style={{ background: '#2e1a1a', border: `1px solid ${T.red}`, marginBottom: 16 }}>
          <div className={s.errorText}>Error: {error}</div>
        </GlassPanel>
      )}

      {/* Impact Estimator */}
      <GlassPanel style={{ marginBottom: 24 }}>
        <div className={s.sectionTitle}>Market Impact Estimator</div>
        <form onSubmit={handleEstimate} className={s.estimatorForm}>
          <div>
            <label className={s.fieldLabel}>Symbol</label>
            <input
              value={estSymbol}
              onChange={e => setEstSymbol(e.target.value.toUpperCase())}
              placeholder="AAPL"
              className={s.input}
            />
          </div>
          <div>
            <label className={s.fieldLabel}>Quantity</label>
            <input
              type="number"
              value={estQty}
              onChange={e => setEstQty(e.target.value)}
              placeholder="1000"
              className={s.input}
            />
          </div>
          <div>
            <label className={s.fieldLabel}>Side</label>
            <select value={estSide} onChange={e => setEstSide(e.target.value)} className={s.select}>
              <option value="BUY">BUY</option>
              <option value="SELL">SELL</option>
            </select>
          </div>
          <button
            type="submit"
            disabled={estLoading || !estSymbol || !estQty}
            className={s.submitBtn}
          >
            {estLoading ? 'Estimating...' : 'Estimate Impact'}
          </button>
        </form>

        {estResult && !estResult.error && (
          <div className={s.estimateGrid}>
            <StatCard label="Est. Impact" value={`${fmt(estResult.estimated_impact_bps, 1)} bps`}
              color={estResult.estimated_impact_bps < 5 ? T.green : estResult.estimated_impact_bps < 20 ? T.amber : T.red} compact />
            <StatCard label="Recommended Algo" value={estResult.recommended_algo || '--'} color={T.blue} compact />
            <StatCard label="Optimal Horizon" value={`${fmt(estResult.optimal_horizon_minutes, 0)} min`} color={T.purple} compact />
            <StatCard label="Participation Rate" value={`${fmt(estResult.participation_rate_pct, 2)}%`} color={T.amber} compact />
            <StatCard label="Avg Daily Volume" value={estResult.avg_daily_volume?.toLocaleString() || '--'} color={T.textSec} compact />
            <StatCard label="Liquidity Score" value={fmt(estResult.liquidity_score, 0)} color={T.green} compact />
          </div>
        )}

        {estResult?.error && (
          <div className={s.estimateError}>Error: {estResult.error}</div>
        )}
      </GlassPanel>

      {/* Active Executions */}
      <GlassPanel style={{ marginBottom: 24 }}>
        <div className={s.sectionTitle}>Active Executions</div>
        {active.length > 0 ? (
          <div className={s.activeList}>
            {active.map((exec, i) => {
              const pct = exec.qty_filled && exec.qty_total ? (exec.qty_filled / exec.qty_total) * 100 : 0;
              return (
                <div key={i} className={s.execCard}>
                  <div className={s.execHeader}>
                    <div className={s.execHeaderLeft}>
                      <span className={s.execSymbol}>{exec.symbol}</span>
                      <AlgoBadge algo={exec.algo} />
                      <span
                        className={s.execSide}
                        style={{ color: exec.side === 'BUY' ? T.green : T.red }}
                      >
                        {exec.side} {exec.qty_total}
                      </span>
                    </div>
                    <span className={s.execPct}>{pct.toFixed(1)}%</span>
                  </div>
                  <ProgressBar pct={pct} color={T.blue} />
                  <div className={s.execMeta}>
                    <span>Filled: {exec.qty_filled || 0}/{exec.qty_total || 0}</span>
                    {exec.avg_price && <span>Avg: ${Number(exec.avg_price).toFixed(2)}</span>}
                    {exec.started_at && <span>Started: {new Date(exec.started_at).toLocaleTimeString()}</span>}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className={s.emptyState}>No active algo executions</div>
        )}
      </GlassPanel>

      {/* Completed Executions */}
      <GlassPanel>
        <div className={s.sectionTitle}>Completed Executions</div>
        {completed.length > 0 ? (
          <div className={s.tableWrap}>
            <table className={s.completedTable}>
              <thead>
                <tr>
                  {['Symbol', 'Algo', 'Side', 'Qty', 'Avg Price', 'VWAP', 'Slippage (bps)', 'Duration', 'Completed'].map(h => (
                    <th key={h} className={s.completedTh}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {completed.map((exec, i) => (
                  <tr key={i} style={{ borderBottom: i < completed.length - 1 ? `1px solid ${T.border}` : 'none' }}>
                    <td className={`${s.completedTd} ${s.completedSymbol}`}>{exec.symbol}</td>
                    <td className={s.completedTd}><AlgoBadge algo={exec.algo} /></td>
                    <td
                      className={`${s.completedTd} ${s.completedSide}`}
                      style={{ color: exec.side === 'BUY' ? T.green : T.red }}
                    >
                      {exec.side}
                    </td>
                    <td className={`${s.completedTd} ${s.completedQty}`}>{exec.qty_total}</td>
                    <td className={`${s.completedTd} ${s.completedPrice}`}>{exec.avg_price ? `$${Number(exec.avg_price).toFixed(2)}` : '--'}</td>
                    <td className={`${s.completedTd} ${s.completedPrice}`}>{exec.vwap ? `$${Number(exec.vwap).toFixed(2)}` : '--'}</td>
                    <td
                      className={`${s.completedTd} ${s.completedSlippage}`}
                      style={{
                        color: (exec.slippage_bps ?? 0) <= 2 ? T.green : (exec.slippage_bps ?? 0) <= 10 ? T.amber : T.red,
                      }}
                    >
                      {exec.slippage_bps != null ? Number(exec.slippage_bps).toFixed(1) : '--'}
                    </td>
                    <td className={`${s.completedTd} ${s.completedDuration}`}>{exec.duration || '--'}</td>
                    <td className={`${s.completedTd} ${s.completedTime}`}>
                      {exec.completed_at ? new Date(exec.completed_at).toLocaleString() : '--'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className={s.emptyState}>No completed algo executions</div>
        )}
      </GlassPanel>
    </div>
  );
}
